                                            <label className="text-[11px] font-bold text-slate-400 flex justify-between uppercase">
                                                <span>Body Text Size</span>
                                                <span className="text-purple-400 font-mono text-xs">{config.imageBodyFontSize}px</span>
                                            </label>
                                            <input type="range" min="30" max="160" step="2" value={config.imageBodyFontSize} onChange={(e) => setConfig({...config, imageBodyFontSize: parseInt(e.target.value)})} className="w-full h-2 bg-slate-800 rounded-lg appearance-none cursor-pointer accent-purple-500" />
                                        </div>
                                    </div>

                                    <div className="pt-4 border-t border-slate-800 space-y-5">
                                        <h3 className="text-sm font-bold text-slate-400 uppercase tracking-wider">Spacing & Borders</h3>
                                        <div className="space-y-2">
                                            <label className="text-[11px] font-bold text-slate-400 flex justify-between uppercase">
                                                <span>Row Vertical Padding</span>
                                                <span className="text-purple-400 font-mono text-xs">{config.imageRowPadding}px</span>
                                            </label>
                                            <input type="range" min="10" max="150" step="5" value={config.imageRowPadding} onChange={(e) => setConfig({...config, imageRowPadding: parseInt(e.target.value)})} className="w-full h-2 bg-slate-800 rounded-lg appearance-none cursor-pointer accent-purple-500" />
                                        </div>
                                        <div className="space-y-2">
                                            <label className="text-[11px] font-bold text-slate-400 flex justify-between uppercase">
                                                <span>Column Horizontal Spacing</span>
                                                <span className="text-purple-400 font-mono text-xs">{config.imageColumnSpacing}px</span>
                                            </label>
                                            <input type="range" min="5" max="250" step="5" value={config.imageColumnSpacing} onChange={(e) => setConfig({...config, imageColumnSpacing: parseInt(e.target.value)})} className="w-full h-2 bg-slate-800 rounded-lg appearance-none cursor-pointer accent-purple-500" />
                                        </div>
                                        <div className="space-y-2">
                                            <label className="text-[11px] font-bold text-slate-400 flex justify-between uppercase">
                                                <span>Border Width</span>
                                                <span className="text-purple-400 font-mono text-xs">{config.imageBorderWidth}px</span>
                                            </label>
                                            <input type="range" min="0" max="20" step="1" value={config.imageBorderWidth} onChange={(e) => setConfig({...config, imageBorderWidth: parseInt(e.target.value)})} className="w-full h-2 bg-slate-800 rounded-lg appearance-none cursor-pointer accent-purple-500" />
                                        </div>
                                    </div>

                                    <div className="pt-4 border-t border-slate-800 space-y-4">
                                        <h3 className="text-sm font-bold text-slate-400 uppercase tracking-wider">Effects</h3>
                                        <div className="space-y-2">
                                            <label className="text-[11px] font-bold text-slate-400 flex justify-between uppercase">
                                                <span>Overlay Opacity</span>
                                                <span className="text-blue-400 font-mono text-xs">{Math.round(config.imageOverlayOpacity * 100)}%</span>
                                            </label>
                                            <input type="range" min="0" max="1" step="0.05" value={config.imageOverlayOpacity} onChange={(e) => setConfig({...config, imageOverlayOpacity: parseFloat(e.target.value)})} className="w-full h-2 bg-slate-800 rounded-lg appearance-none cursor-pointer accent-blue-500" />
                                        </div>
                                        <div className="flex justify-between items-center p-3 bg-slate-800 rounded-lg border border-slate-700">
                                            <label className="text-sm text-slate-300">Show App Name</label>
                                            <input type="checkbox" checked={config.showAppName} onChange={(e) => setConfig({...config, showAppName: e.target.checked})} className="w-5 h-5 rounded cursor-pointer" />
                                        </div>
                                    </div>

                                    <div className="space-y-2 pt-4 border-t border-slate-800">
                                        <div className="flex justify-between items-center">
                                            <div className="text-xs text-slate-500 font-semibold uppercase flex items-center gap-2">Background Image</div>
                                            {config.backgroundImage && <button onClick={() => setConfig({...config, backgroundImage: undefined})} className="text-[10px] text-red-400">Remove</button>}
                                        </div>

                                        {config.backgroundImage ? (
                                            <div className="relative w-full h-24 rounded-lg overflow-hidden border border-slate-700 group">
                                                <img src={config.backgroundImage} className="w-full h-full object-cover" alt="Background"/>
                                                <div className="absolute inset-0 bg-black/40 flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity">
                                                    <button onClick={() => bgInputRef.current?.click()} className="bg-white/20 p-2 rounded-full"><Upload size={16} /></button>
                                                </div>
                                            </div>
                                        ) : (
                                            <div className="flex gap-2">
                                                <button onClick={handleGenerateBackground} disabled={isGenImage || !data.title} className="flex-1 py-3 border border-dashed border-slate-700 rounded-lg text-slate-500 hover:text-blue-400 flex flex-col items-center justify-center gap-1">
                                                    {isGenImage ? <Loader2 size={16} className="animate-spin"/> : <Wand2 size={16}/>}
                                                    <span className="text-[10px]">AI Generated</span>
                                                </button>
                                                <button onClick={() => bgInputRef.current?.click()} className="flex-1 py-3 border border-dashed border-slate-700 rounded-lg text-slate-500 hover:text-purple-400 flex flex-col items-center justify-center gap-1">
                                                    <Upload size={16}/>
                                                    <span className="text-[10px]">Upload Image</span>
                                                </button>
                                            </div>
                                        )}
                                    </div>
                                </>
                            )}
                        </div>
                     </div>
                )}
            </div>
          </div>
        )}
      </main>
    </div>
  );
}

export default App;

import React, { useState, useRef, useEffect, useMemo } from 'react';
import { Play, Pause, Download, Wand2, Maximize2, Minimize2, Loader2, Clock, Film, Shuffle, Sparkles, LayoutTemplate, Database, Palette, ImageIcon, Mic, Volume2, Image as ImageDown, Globe, RefreshCw, Type, Bot, Music, FileUp, UploadCloud, Layers, Upload, Eye, EyeOff, Video, CheckSquare, Square, Pin, Edit3, Camera, X, Save, Cloud, DownloadCloud } from 'lucide-react';
import { TableData, AnimationConfig, Theme, AnimationStyle, Layout, ImageStyle, BgVisibility } from './types';
import { DEFAULT_TABLE_DATA, DEFAULT_ANIMATION_CONFIG } from './constants';
import { TablePreview } from './components/TablePreview';
import { ImagePreview } from './components/ImagePreview';
import { Editor } from './components/Editor';
import { DataEditorModal } from './components/DataEditorModal';
import { SavedTablesModal } from './components/SavedTablesModal';
import { generateTableFromPrompt, fixTableJson, generateBackgroundImage, generateVoiceover, generateSummaryFromData, generateTableFromImage } from './services/geminiService';
import { saveTableToFirestore } from './services/firebaseService';
import { renderVideo } from './utils/videoRenderer';
import { renderTableImage } from './utils/imageRenderer';
import { createWavBlob } from './utils/audioSynth';
import { clsx } from 'clsx';

const AVAILABLE_VOICES = ['Kore', 'Puck', 'Charon', 'Fenrir', 'Zephyr'];

function App() {
  const [data, setData] = useState<TableData>(DEFAULT_TABLE_DATA);
  const [jsonString, setJsonString] = useState<string>(JSON.stringify(DEFAULT_TABLE_DATA, null, 2));
  const [isValidJson, setIsValidJson] = useState(true);
  const [jsonError, setJsonError] = useState<string | null>(null);

  const [isPlaying, setIsPlaying] = useState(false);
  const [isFullscreen, setIsFullscreen] = useState(false);
  const [isGenerating, setIsGenerating] = useState(false);
  const [isAnalyzingImage, setIsAnalyzingImage] = useState(false);
  const [isDataEditorOpen, setIsDataEditorOpen] = useState(false);
  const [isSavedTablesOpen, setIsSavedTablesOpen] = useState(false);

  const [isExporting, setIsExporting] = useState(false); 
  const [exportProgress, setExportProgress] = useState(0);
  const [isSaving, setIsSaving] = useState(false);

  const [prompt, setPrompt] = useState("");
  const [showPromptInput, setShowPromptInput] = useState(false);

  const [config, setConfig] = useState<AnimationConfig>(DEFAULT_ANIMATION_CONFIG);

  const [sidebarTab, setSidebarTab] = useState<'data' | 'design'>('data');
  const [viewMode, setViewMode] = useState<'video' | 'image'>('video');

  const [isGenImage, setIsGenImage] = useState(false);
  const [isGenVoice, setIsGenVoice] = useState(false);
  const [voicePcm, setVoicePcm] = useState<string | null>(null);
  const [narrativeLanguage, setNarrativeLanguage] = useState<'auto' | 'en' | 'ne'>('auto');
  const [selectedVoice, setSelectedVoice] = useState('Kore');

  // Camera State
  const [showCamera, setShowCamera] = useState(false);
  const [cameraStream, setCameraStream] = useState<MediaStream | null>(null);
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);

  const appContainerRef = useRef<HTMLDivElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const bgInputRef = useRef<HTMLInputElement>(null);

  // Derive filtered table data based on selected columns for image preview
  const filteredImageData = useMemo(() => {
    if (viewMode !== 'image') return data;
    const indices = config.selectedColumnIndices || [0];
    const finalIndices = config.pinFirstColumn && !indices.includes(0) ? [0, ...indices] : indices;

    // Fix: Explicitly type Array.from to resolve 'unknown' indexing issues and provide sort comparator
    const sortedIndices: number[] = Array.from<number>(new Set(finalIndices)).sort((a, b) => a - b);

    return {
      ...data,
      columns: sortedIndices.map((i: number) => data.columns[i] || `Col ${i}`),
      data: data.data.map(row => sortedIndices.map((i: number) => row[i] || ""))
    };
  }, [data, config.selectedColumnIndices, config.pinFirstColumn, viewMode]);

  const handleJsonChange = (newJson: string) => {
    setJsonString(newJson);
    try {
      const parsed = JSON.parse(newJson);
      if (parsed.columns && Array.isArray(parsed.columns) && parsed.data && Array.isArray(parsed.data)) {
        setData(parsed);
        setIsValidJson(true);
        setJsonError(null);
        // Reset column weights if columns changed and select all columns by default
        if (parsed.columns.length !== data.columns.length) {
          setConfig(prev => ({ 
            ...prev, 
            columnWeights: undefined,
            selectedColumnIndices: parsed.columns.map((_: any, i: number) => i)
          }));
        }
      } else {
        throw new Error("Missing 'columns' or 'data' array.");
      }
    } catch (e: any) {
      setIsValidJson(false);
      setJsonError(e.message);
    }
  };

  const handleDataEditorSave = (newData: TableData) => {
    setData(newData);
    setJsonString(JSON.stringify(newData, null, 2));
    setIsValidJson(true);
    setJsonError(null);
    // Refresh column selection if columns count changed - select all columns
    if (newData.columns.length !== data.columns.length) {
       setConfig(prev => ({ 
         ...prev, 
         selectedColumnIndices: newData.columns.map((_: any, i: number) => i),
         columnWeights: undefined 
       }));
    }
  };

  const handleCloudSave = async () => {
    if (!data.title) {
        alert("Please add a title to your table before saving.");
        return;
    }
    setIsSaving(true);
    try {
        await saveTableToFirestore(data);
        alert("Table saved to Cloud Library successfully!");
    } catch (e) {
        alert("Failed to save to cloud.");
        console.error(e);
    } finally {
        setIsSaving(false);
    }
  };

  const handleCloudLoad = (loadedData: TableData) => {
    setData(loadedData);
    setJsonString(JSON.stringify(loadedData, null, 2));
    setIsValidJson(true);
    setJsonError(null);
    setConfig(prev => ({ 
        ...prev, 
        columnWeights: undefined,
        backgroundImage: undefined,
        selectedColumnIndices: loadedData.columns.map((_: any, i: number) => i)
    }));
  };

  const handleGenerate = async () => {
    if (!prompt.trim()) return;
    setIsGenerating(true);
    try {
      const newData = await generateTableFromPrompt(prompt);
      const formatted = JSON.stringify(newData, null, 2);
      setJsonString(formatted);
      setData(newData);
      setIsValidJson(true);
      setShowPromptInput(false);
      setVoicePcm(null); 
      setConfig(prev => ({ 
        ...prev, 
        backgroundImage: undefined, 
        columnWeights: undefined,
        selectedColumnIndices: newData.columns.map((_: any, i: number) => i)
      }));
    } catch (error) {
      const errMsg = error instanceof Error ? error.message : String(error);
      if (errMsg.includes('429')) {
         alert("API Quota Exceeded. Please wait a moment.");
      } else {
         alert("Failed to generate table.");
      }
    } finally {
      setIsGenerating(false);
    }
  };

  const processImagesForTable = async (base64Images: string[]) => {
    if (base64Images.length === 0) return;
    setIsAnalyzingImage(true);
    try {
      const newData = await generateTableFromImage(base64Images);
      if (newData.data && Array.isArray(newData.data) && newData.data.length > 0) {
        // Randomize row order for variety if needed, but keeping it simple for now or preserving order if implied.
        // Actually, let's keep the order returned by AI as it might be sequential across pages.
      }
      const formatted = JSON.stringify(newData, null, 2);
      setJsonString(formatted);
      setData(newData);
      setIsValidJson(true);
      setShowPromptInput(false);
      setVoicePcm(null);
      setConfig(prev => ({ 
        ...prev, 
        backgroundImage: undefined, 
        columnWeights: undefined,
        selectedColumnIndices: newData.columns.map((_: any, i: number) => i)
      }));
    } catch (error) {
      alert("Could not extract table data from image(s).");
    } finally {
      setIsAnalyzingImage(false);
    }
  };

  const handleImageUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    if (!files || files.length === 0) return;

    const base64Promises: Promise<string>[] = [];

    for (let i = 0; i < files.length; i++) {
        const file = files[i];
        base64Promises.push(new Promise((resolve) => {
            const reader = new FileReader();
            reader.onload = (event) => resolve(event.target?.result as string);
            reader.readAsDataURL(file);
        }));
    }

    try {
        const base64Images = await Promise.all(base64Promises);
        await processImagesForTable(base64Images);
    } catch (err) {
        console.error("Error processing uploads", err);
    }

    e.target.value = "";
  };

  const handleBgUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (event) => {
        const base64 = event.target?.result as string;
        if (base64) setConfig(prev => ({ ...prev, backgroundImage: base64 }));
    };
    reader.readAsDataURL(file);
    e.target.value = "";
  };

  useEffect(() => {
    const handlePaste = async (e: ClipboardEvent) => {
        const items = e.clipboardData?.items;
        if (!items) return;

        const base64Promises: Promise<string>[] = [];

        for (let i = 0; i < items.length; i++) {
            if (items[i].type.indexOf("image") !== -1) {
                const blob = items[i].getAsFile();
                if (blob) {
                    base64Promises.push(new Promise((resolve) => {
                         const reader = new FileReader();
                         reader.onload = (event) => resolve(event.target?.result as string);
                         reader.readAsDataURL(blob);
                    }));
                }
            }
        }

        if (base64Promises.length > 0) {
            e.preventDefault();
            try {
                const base64Images = await Promise.all(base64Promises);
                await processImagesForTable(base64Images);
            } catch(err) {
                console.error("Error processing pasted images", err);
            }
        }
    };
    window.addEventListener('paste', handlePaste);
    return () => window.removeEventListener('paste', handlePaste);
  }, []);

  const handleFixJson = async () => {
    setIsGenerating(true);
    try {
      const fixedData = await fixTableJson(jsonString);
      setJsonString(JSON.stringify(fixedData, null, 2));
      setData(fixedData);
      setIsValidJson(true);
      setJsonError(null);
      setConfig(prev => ({ 
        ...prev, 
        columnWeights: undefined,
        selectedColumnIndices: fixedData.columns.map((_: any, i: number) => i)
      }));
    } catch (error) {
      alert("Could not fix JSON automatically.");
    } finally {
      setIsGenerating(false);
    }
  };

  const handleGenerateBackground = async () => {
      if (!data.title) return;
      setIsGenImage(true);
      try {
          const base64Img = await generateBackgroundImage(data.title);
          setConfig(prev => ({ ...prev, backgroundImage: base64Img }));
      } catch (e) {
          alert("Failed to generate image.");
      } finally {
          setIsGenImage(false);
      }
  };

  const handleRegenerateSummary = async () => {
      setIsGenVoice(true);
      try {
          const summary = await generateSummaryFromData(data, narrativeLanguage);
          const newData = { ...data, summary };
          setData(newData);
          setJsonString(JSON.stringify(newData, null, 2));
          setVoicePcm(null);
      } catch(e) {
          alert("Failed to regenerate summary.");
      } finally {
          setIsGenVoice(false);
      }
  };

  const handleGenerateVoice = async () => {
      setIsGenVoice(true);
      try {
          let summaryText = data.summary;
          if (!summaryText || summaryText.trim() === '') {
              summaryText = await generateSummaryFromData(data, narrativeLanguage);
              const newData = { ...data, summary: summaryText };
              setData(newData);
              setJsonString(JSON.stringify(newData, null, 2));
          }
          if (summaryText) {
            const pcm = await generateVoiceover(summaryText, selectedVoice);
            setVoicePcm(pcm);
          }
      } catch (e) {
          alert("Failed to generate voiceover.");
      } finally {
          setIsGenVoice(false);
      }
  };

  const handleRandomizeDesign = () => {
    const themes = Object.values(Theme);
    const styles = Object.values(AnimationStyle);
    const layouts = Object.values(Layout);
    setConfig(prev => ({
        ...prev,
        theme: themes[Math.floor(Math.random() * themes.length)],
        style: styles[Math.floor(Math.random() * styles.length)],
        layout: layouts[Math.floor(Math.random() * layouts.length)],
        columnWeights: undefined
    }));
  };

  const toggleFullscreen = () => {
    if (!document.fullscreenElement) {
      appContainerRef.current?.requestFullscreen().then(() => setIsFullscreen(true));
    } else {
      document.exitFullscreen().then(() => setIsFullscreen(false));
    }
  };

  useEffect(() => {
    const handler = () => setIsFullscreen(!!document.fullscreenElement);
    document.addEventListener('fullscreenchange', handler);
    return () => document.removeEventListener('fullscreenchange', handler);
  }, []);

  const handleExportVideo = async () => {
    if (isExporting) return;
    setIsExporting(true);
    setExportProgress(0);
    setIsPlaying(false);
    try {
        const blob = await renderVideo(data, config, voicePcm, (p) => setExportProgress(Math.round(p * 100)));
        const url = URL.createObjectURL(blob);
        const a = document.createElement('a');
        a.href = url;
        a.download = `loksewa-${config.theme}-${Date.now()}.mp4`;
        a.click();
        URL.revokeObjectURL(url);
    } catch (err: any) {
        alert("Export failed: " + err.message);
    } finally {
        setIsExporting(false);
        setExportProgress(0);
    }
  };

  const handleExportImage = async () => {
      if (isExporting) return;
      setIsExporting(true);
      try {
          const indices = config.selectedColumnIndices || [0];
          const pinFirst = config.pinFirstColumn;
          const secondaryIndices = pinFirst ? indices.filter(i => i !== 0) : indices;

          if (config.exportSplitColumns && secondaryIndices.length > 1) {
              const baseTitle = data.title || "Export";
              const primaryIdx = pinFirst ? 0 : -1;
              const primaryCol = primaryIdx !== -1 ? data.columns[primaryIdx] : null;

              for (const secIdx of secondaryIndices) {
                  const finalCols = primaryCol !== null ? [primaryCol, data.columns[secIdx]] : [data.columns[secIdx]];
                  const finalRows = data.data.map(row => primaryIdx !== -1 ? [row[primaryIdx], row[secIdx]] : [row[secIdx]]);

                  const partialData: TableData = {
                      ...data,
                      title: baseTitle, 
                      columns: finalCols,
                      data: finalRows
                  };
                  // renderTableImage now returns array
                  const dataUrls = await renderTableImage(partialData, config);

                  for (let i = 0; i < dataUrls.length; i++) {
                      const a = document.createElement('a');
                      a.href = dataUrls[i];
                      const suffix = dataUrls.length > 1 ? `_part${i+1}` : '';
                      a.download = `post-${data.columns[secIdx].replace(/[^a-z0-9]/gi, '_').toLowerCase()}${suffix}.png`;
                      document.body.appendChild(a);
                      a.click();
                      document.body.removeChild(a);
                      await new Promise(r => setTimeout(r, 600)); // Delay for browser
                  }
              }
          } else {
              // Standard single export with all selected columns
              const dataUrls = await renderTableImage(filteredImageData, config);
              for (let i = 0; i < dataUrls.length; i++) {
                  const a = document.createElement('a');
                  a.href = dataUrls[i];
                  const suffix = dataUrls.length > 1 ? `_part${i+1}` : '';
                  a.download = `loksewa-post-${Date.now()}${suffix}.png`;
                  document.body.appendChild(a);
                  a.click();
                  document.body.removeChild(a);
                  await new Promise(r => setTimeout(r, 600));
              }
          }
      } catch (e) {
          alert("Failed to export image(s)");
      } finally {
          setIsExporting(false);
      }
  };

  const toggleColumnSelection = (idx: number) => {
      const current = config.selectedColumnIndices || [];
